// src/pages/RegisterManageSub1Page.js
import React, { useEffect, useState } from 'react';
import axios from 'axios';
import { useNavigate } from 'react-router-dom';
import * as XLSX from 'xlsx';

import './RegisterManageSub1Page.css';

function RegisterManageSub1Page() {
  const [woods, setWoods] = useState([]);
  const [filter, setFilter] = useState('');
  const [selectedProvince, setSelectedProvince] = useState('');
  const [selectedCommune, setSelectedCommune] = useState('');
  const [selectedSpecies, setSelectedSpecies] = useState('');
  const [selectedLoaiCoSoDangKy] = useState('Đăng ký cơ sở kinh doanh, chế biến gỗ');
  const [selectedNganhNgheKinhDoanhGo, setSelectedNganhNgheKinhDoanhGo] = useState('');
  const [selectedTrangThai, setSelectedTrangThai] = useState('');
  const [selectedLoaiHinhCheBienGo, setSelectedLoaiHinhCheBienGo] = useState('');
  const [selectedNguonGocGo, setSelectedNguonGocGo] = useState('');

  const [uniqueProvinces, setUniqueProvinces] = useState([]);
  const [uniqueCommunes, setUniqueCommunes] = useState([]);
  const [uniqueSpecies, setUniqueSpecies] = useState([]);
  const [uniqueNganhNgheKinhDoanhGo, setUniqueNganhNgheKinhDoanhGo] = useState([]);
  const [uniqueTrangThai, setUniqueTrangThai] = useState([]);
  const [uniqueLoaiHinhCheBienGo, setUniqueLoaiHinhCheBienGo] = useState([]);
  const [uniqueNguonGocGo, setUniqueNguonGocGo] = useState([]);

  const navigate = useNavigate();
  const token = localStorage.getItem('token');

  const initialColumnsConfig = {
    tinhThanhPho: { id: 'tinhThanhPho', label: 'Tỉnh (TP)', visible: true, minWidth: '100px' },
    xaPhuong: { id: 'xaPhuong', label: 'Xã (Phường)', visible: true, minWidth: '100px' },
    diaChiCoSo: { id: 'diaChiCoSo', label: 'Địa chỉ cơ sở', visible: true, minWidth: '220px' },
    tenCoSo: { id: 'tenCoSo', label: 'Tên cơ sở', visible: true, minWidth: '180px' },
    vido: { id: 'vido', label: 'Vĩ độ', visible: true, minWidth: '80px' },
    kinhdo: { id: 'kinhdo', label: 'Kinh độ', visible: true, minWidth: '80px' },
    ngayThanhLap: { id: 'ngayThanhLap', label: 'Ngày thành lập', visible: true, minWidth: '100px' },
    giayPhepKinhDoanh: { id: 'giayPhepKinhDoanh', label: 'Số GPKD', visible: true, minWidth: '100px' },
    tenNguoiDaiDien: { id: 'tenNguoiDaiDien', label: 'Người đại diện', visible: true, minWidth: '150px' },
    namSinh: { id: 'namSinh', label: 'Năm sinh', visible: true, minWidth: '80px' },
    soCCCD: { id: 'soCCCD', label: 'Số CCCD/Hộ chiếu', visible: true, minWidth: '120px' },
    ngayCapCCCD: { id: 'ngayCapCCCD', label: 'Ngày cấp CCCD', visible: true, minWidth: '100px' },
    noiCapCCCD: { id: 'noiCapCCCD', label: 'Nơi cấp CCCD', visible: true, minWidth: '120px' },
    soDienThoaiNguoiDaiDien: { id: 'soDienThoaiNguoiDaiDien', label: 'SĐT Người đại diện', visible: true, minWidth: '120px' },
    diaChiNguoiDaiDien: { id: 'diaChiNguoiDaiDien', label: 'Địa chỉ Người đại diện', visible: true, minWidth: '180px' },
    loaiHinhKinhDoanhGo: { id: 'loaiHinhKinhDoanhGo', label: 'Loại hình KD gỗ', visible: false, minWidth: '120px' },
    nganhNgheKinhDoanhGo: { id: 'nganhNgheKinhDoanhGo', label: 'Ngành nghề KD gỗ', visible: false, minWidth: '120px' },
    loaiHinhCheBienGo: { id: 'loaiHinhCheBienGo', label: 'Loại hình chế biến', visible: false, minWidth: '120px' },
    nguonGocGo: { id: 'nguonGocGo', label: 'Nguồn gốc gỗ', visible: false, minWidth: '120px' },
	  khoiLuong: { id: 'khoiLuong', label: 'Khối lượng', visible: true, minWidth: '80px' },
    tenLamSan: { id: 'tenLamSan', label: 'Tên lâm sản', visible: true, minWidth: '150px' },
    tenKhoaHoc: { id: 'tenKhoaHoc', label: 'Tên khoa học', visible: true, minWidth: '180px' },
    trangThai: { id: 'trangThai', label: 'Trạng thái', visible: true, minWidth: '100px' },
    ghiChu: { id: 'ghiChu', label: 'Ghi chú', visible: false, minWidth: '200px' },
    actions: { id: 'actions', label: '🛠️', visible: true, width: '210px', minWidth: '210px', maxWidth: '210px' },
  };

  const [columns, setColumns] = useState(initialColumnsConfig);
  const [showColumnOptions, setShowColumnOptions] = useState(false);
  const [currentPage, setCurrentPage] = useState(1);
  const [itemsPerPage, setItemsPerPage] = useState(15);

  useEffect(() => {
    // ... Giữ nguyên logic của bạn ...
  }, []);

  useEffect(() => {
    // ... Giữ nguyên logic của bạn ...
  }, [columns]);

  useEffect(() => {
    const fetchWoodBusinesses = async () => {
      // ... Giữ nguyên logic của bạn ...
    };

    if (token) {
      fetchWoodBusinesses();
    } else {
      navigate('/');
    }
  }, [token, navigate, selectedLoaiCoSoDangKy, selectedTrangThai]);

  const handleDelete = async (id) => {
    // ... Giữ nguyên logic của bạn ...
  };

  const handleEdit = (id) => navigate(`/edit-wood-business/${id}`);
  const handleNavigateToWoodDetail = (id) => navigate(`/admin/woods/${id}`);

  // === HÀM MỚI ĐÃ ĐƯỢC THÊM VÀO ===
  const handleAddProduct = (farmId) => {
    navigate(`/farm/${farmId}/add-product`);
  };

  // ... Các logic và hàm còn lại giữ nguyên ...

  return (
    <div className="farm-list-container">
      <h2>📋 Danh sách cơ sở kinh doanh, chế biến gỗ</h2>

      <div className="filter-container">
        {/* ... Giữ nguyên các bộ lọc của bạn ... */}
      </div>

      {showColumnOptions && (
        <div className="column-options-container">
          {/* ... Giữ nguyên phần ẩn/hiện cột của bạn ... */}
        </div>
      )}

      {currentItems.length > 0 ? (
        <table border="1" cellPadding="8" className="table-auto w-full border-collapse">
          <thead>
            <tr>
              {Object.values(columns).map(col => col.visible && (
                <th key={col.id} style={{ minWidth: col.minWidth, width: col.minWidth }}>{col.label}</th>
              ))}
            </tr>
          </thead>
          <tbody>
            {currentItems.map((item) => (
              <tr key={item._id}>
                {Object.values(columns).map(col => col.visible && (
                  <td key={col.id}>
                    {col.id === 'actions' ? (
                      // === PHẦN NÚT HÀNH ĐỘNG ĐÃ ĐƯỢC CẬP NHẬT ===
                      <div className="action-buttons-cell">
                        <button onClick={() => handleNavigateToWoodDetail(item._id)} className="action-button view-button">Nhập, xuất</button>{' '}
                        <button onClick={() => handleEdit(item._id)} className="action-button edit-button">✏️</button>{' '}
                        <button 
                          onClick={() => handleAddProduct(item._id)} 
                          className="action-button add-product-button"
                          title="Thêm Lâm sản mới"
                        >
                          ➕🌲
                        </button>
                        <button onClick={() => handleDelete(item._id)} className="action-button delete-button">🗑️</button>
                      </div>
                    ) : (
                      ['ngayThanhLap', 'ngayCapCCCD'].includes(col.id) ? (item[col.id] ? new Date(item[col.id]).toLocaleDateString() : '') : item[col.id]
                    )}
                  </td>
                ))}
              </tr>
            ))}
          </tbody>
        </table>
      ) : (
        <p>Không có cơ sở nào phù hợp với bộ lọc.</p>
      )}

      {filteredWoods.length > 0 && (
        <div className="pagination-container">
            {/* ... Giữ nguyên phần phân trang của bạn ... */}
        </div>
      )}
    </div>
  );
}

export default RegisterManageSub1Page;
